import { Component, Event, EventEmitter, Prop, Host, h } from '@stencil/core';
import { isNullOrUndefined, isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';


@Component({
  tag: 'mx-sliding-panel',
  styleUrl: './mx-sliding-panel.css',
  shadow: false
})
export class MxSlidingPanel {
  /** Positions to the left or right of content. */
  @Prop() readonly align: 'left' | 'right' = 'left';

  /** Applies a fixed position. */
  @Prop() readonly overlap: boolean = false;

  /** Determines if panel is open. */
  @Prop({ mutable: true }) open: boolean = false;

  /** Defines title text. */
  @Prop() readonly panelTitle!: string;

  /** Defines icon. */
  @Prop() readonly icon: string = 'kds-icon-filters';

  /** Defines the icon used to close the sliding panel. */
  @Prop() readonly closeIcon: string = 'kds-icon-close';

  /** Determines if badge displayed and what its value is. */
  @Prop() readonly badgeValue: number = 0;

  /** Sets aria label when badge is defined, i.e., "filters selected" or "messages unread". */
  @Prop() readonly badgeLabel: string;

  /** Defines the custom width of the open panel in `rem` units. */
  @Prop() readonly panelWidth: number;

  /** Applies a hidden attribute and class to the component if true and is panel is closed. */
  @Prop() readonly hideCollapsedPanel: boolean = false;

  /** Defines the heading level in relation to the layout it's being placed. */
  @Prop() readonly headingLevel: 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6' = 'h3';

  /** Sets primary background for the panel */
  @Prop() readonly hasBackground: boolean = true;

  /** Sets css class for the sliding panel header */
  @Prop() readonly headerCssClass: string = '';

  /** Sets css class for the button inside sliding panel header */
  @Prop() readonly headerButtonCssClass: string = '';

  /** Determines to show border for  panel */
  @Prop() readonly showBorder: boolean = true;

  private validateBadgeLabel() {
    if (this.badgeValue > 0 && isNullOrUndefinedOrEmptyString(this.badgeLabel)) {
      console.error(
        `🚨 Accessibility No-No: You must set a badge-label on mx-sliding-panel if badge-value is set.`
      );
    }
  }

  /** Toggles open/close state. */
  @Event() slidingPanelToggled: EventEmitter<any>;

  private togglePanel() {
    this.open = !this.open;
    this.slidingPanelToggled.emit({ open: this.open });
  }

  render() {
    const HeadingTag = this.headingLevel;
    const Icon = this.icon;
    const CloseIcon = this.closeIcon;
    this.validateBadgeLabel();

    return (
      <Host
        class={{
          'mx-SlidingPanel': true,
          'border-solid': this.showBorder,
          'border-r': this.showBorder && this.align !== "right",
          'border-l': this.showBorder && this.align === "right",
          open: this.open,
          [`mx-SlidingPanel--${this.align}`]: true,
          'mx-SlidingPanel--absolute': this.overlap,
          'mx-SlidingPanel--withBorder': this.showBorder,
          hidden: this.hideCollapsedPanel && !this.open
        }}
        hidden={this.hideCollapsedPanel && !this.open}
        style={
          this.open && !isNullOrUndefined(this.panelWidth) && { width: `${this.panelWidth}rem` }
        }
        role='group'
        aria-label={this.panelTitle}
      >
        <header
          class={{
            'mx-SlidingPanel-header': true,
            'border-solid': true,
            'border-b': this.open,
            [this.headerCssClass]: true,
            'bg-primary': this.hasBackground || this.open
          }}
        >
          {this.open && (
            <HeadingTag
              class='mx-SlidingPanel-heading kds-Paragraph--m'
              role='heading'
            >
              {this.panelTitle}
            </HeadingTag>
          )}

          <kds-button
            buttonClass={[
              !this.open && this.badgeValue > 0 ? 'kds-Button--hasIconOnly' : '',
              this.headerButtonCssClass
            ].join(' ')}
            class={{
              "mx-SlidingPanel-headerButton": true,
              "mx-SlidingPanel-headerButton--right": this.align === "right",
              "mx-SlidingPanel-headerButton--left": this.align !== "right"
            }}
            palette='brand'
            kind='prominent'
            variant='fill'
            inverse
            onClick={() => this.togglePanel()}
            inner-aria-label={`${this.panelTitle} ${this.badgeValue ? this.badgeValue : ""
            } ${this.badgeLabel ? this.badgeLabel : ""}`}
            inner-aria-expanded={`${this.open}`}
          >
            {!this.open && this.badgeValue > 0 && (
              <kds-badge
                class={{ "mr-8": this.align === "right" }}
                count={this.badgeValue}
              >
                <Icon size='m' />
              </kds-badge>
            )}

            {!this.open && this.badgeValue === 0 && <Icon size='m' />}

            {this.open && <CloseIcon size='m' />}
          </kds-button>
        </header>
        <div class='mx-SlidingPanel-body' hidden={!this.open}>
          <slot />
        </div>
      </Host>
    );
  }
}
