import { isNullOrUndefined } from '@src/utils/mx-utils/utils';
import { TreeMenuItem } from './menu-item.interface';
import isEqual from 'lodash.isequal';

export function findRootParent(item: TreeMenuItem) {
  while (!isNullOrUndefined(item.parent)) {
    item = item.parent;
  }
  return item;
}

export function getInvalidChildCount(item: TreeMenuItem) {
  let count = 0;
  item.children?.forEach((child) => {
    if (child.disabled) {
      count++;
    }
    count += getInvalidChildCount(child);
  });
  return count;
}

export function isMenuItem(item: any) {
  if (!isNullOrUndefined(item)) {
    const hasLabel = !isNullOrUndefined(item.label);
    const hasValue = !isNullOrUndefined(item.value);
    return hasLabel && hasValue;
  }
}

export function getAllChildrenLabels(parent: TreeMenuItem, allChildren: string[]) {
  if (isNullOrUndefined(parent.children)) {
    allChildren.push(parent.label);
    return;
  }
  parent.children.forEach((child) => {
    if (isNullOrUndefined(child.children)) {
      getAllChildrenLabels(child, allChildren);
    } else {
      allChildren.push(child.label);
    }
  });
}

export function getAllChildrenFromList(items: any[]) {
  const allChildren: string[] = [];
  if (!isNullOrUndefined(items) && items.length > 0) {
    items.forEach((item) => getAllChildrenLabels(item, allChildren));
  }
  return allChildren;
}

export function removeChildInArrayByLabel(items: any[], childLabel: string) {
  if (!isNullOrUndefined(items) && !isNullOrUndefined(childLabel)) {
    for (const item of items) {
      if (item.label === childLabel) {
        items.splice(items.indexOf(item), 1);
        break;
      }
      if (!isNullOrUndefined(item.children) && item.children.length > 0) {
        removeChildInArrayByLabel(item.children, childLabel);
      }
    }
  }
}

export function removeChildInArrayByUuid(items: any[], childUuid: string) {
  if (!isNullOrUndefined(items) && !isNullOrUndefined(childUuid)) {
    for (const item of items) {
      if (item.uuid === childUuid) {
        items.splice(items.indexOf(item), 1);
        break;
      }
      if (!isNullOrUndefined(item.children) && item.children.length > 0) {
        removeChildInArrayByUuid(item.children, childUuid);
      }
    }
  }
}

export function removeItemsWithEmptyChildren(items: TreeMenuItem[]) {
  if (!isNullOrUndefined(items)) {
    return items.filter((item) => {
      if (isNullOrUndefined(item.children) || (!isNullOrUndefined(item.children) && item.children.length > 0)) {
        return item;
      }
    });
  }
}

export function removeItemsWithEmptyChildrenInPlace(items: TreeMenuItem[], deepRecursion = true) {
  if (!isNullOrUndefined(items)) {
    if (!deepRecursion || items.length === 0) {
      items.forEach((item) => {
        if (!isNullOrUndefined(item.children) && item.children.length === 0) {
          const index = items.indexOf(item);
          items.splice(index, 1);
        }
      });
    } else {
      items.forEach((item) => {
        if (!isNullOrUndefined(item.children)) {
          if (item.children.length === 0) {
            const index = items.indexOf(item);
            items.splice(index, 1);
          } else {
            removeItemsWithEmptyChildrenInPlace(item.children);
          }
        }
      });
      if (items.length > 0 && !isNullOrUndefined(items[0].children)) {
        removeItemsWithEmptyChildrenInPlace(items, false);
      }
    }
  }
}

export function convertArrayOfStrings(items: string[]) {
  return items.map((item) => {
    return { label: item, value: item };
  });
}

export function setDisplayChildrenStatus(item: TreeMenuItem, status: boolean) {
  if (!isNullOrUndefined(item.children) && item.children.length > 0) {
    item.displayChildren = status;
    item.children.forEach((child) => {
      setDisplayChildrenStatus(child, status);
    });
  }
}

export function setParentStatus(parent: TreeMenuItem, recursively = true) {
  if (isNullOrUndefined(parent)) {
    return;
  }
  const totalChildren = parent.children.length;
  const partiallySelectedChildren = parent.children.filter((child) => child.indeterminate).length;
  const fullySelectedChildren = parent.children.filter((child) => child.selected || child.indeterminate).length;
  if (partiallySelectedChildren > 0) {
    parent.indeterminate = true;
    parent.selected = false;
  } else if (fullySelectedChildren === 0) {
    parent.indeterminate = false;
    parent.selected = false;
  } else {
    parent.selected = totalChildren === fullySelectedChildren;
    parent.indeterminate = totalChildren !== fullySelectedChildren;
  }
  if (recursively) {
    setParentStatus(parent.parent);
  }
}

export function findItemInArrayByUuid(items: TreeMenuItem[] = [], uuid: string) {
  let result: TreeMenuItem;
  items.some(
    (child) =>
      (child.uuid === uuid && (result = child)) ||
      (result = findItemInArrayByUuid(child.children || [], uuid))
  );
  return result;
}

export function unselectItemAndChildren(item: TreeMenuItem) {
  item.selected = false;
  item.indeterminate = false;
  if (!isNullOrUndefined(item.children)) {
    item.children.forEach((child) => unselectItemAndChildren(child));
  }
}

export function getAllSelectedChildren(item: TreeMenuItem, result: TreeMenuItem[]) {
  if (item.selected) {
    result.push({ label: item.label, value: item.value, uuid: item.uuid });
    // If the item doesn't have a parent, we don't need to worry about any children.
    // This is because if the parent is selected, all children must be selected.
    if (isNullOrUndefined(item.parent)) {
      return;
    }
  }
  for (let i = 0; i < Object.keys(item).length; i++) {
    if (typeof item[Object.keys(item)[i]] == 'object') {
      getAllSelectedChildren(item[Object.keys(item)[i]], result);
    }
  }
}

export function retrieveAllSelectedChildren(items: TreeMenuItem[], selectedItems: TreeMenuItem[]) {
  items.forEach((item) => {
    if (isNullOrUndefined(item.children)) {
      if (item.selected) {
        selectedItems.push(item);
      }
    } else {
      retrieveAllSelectedChildren(item.children, selectedItems);
    }
  });
}

// this will copy uuid from item to selected items and return
export const copyUuidFromItemToSelectedItem = (selectedItems: TreeMenuItem[] = [],
  items: TreeMenuItem[] = []): TreeMenuItem[] => {
  return selectedItems.map((selectedItem) => {
    const matchingItem = items.find((item) =>
      isEqual(item.label, selectedItem.label) &&
      isEqual(item.value, selectedItem.value)
    );
    if (matchingItem) {
      const updatedItem: TreeMenuItem = {
        ...selectedItem,
        uuid: matchingItem.uuid
      };
      if (selectedItem.children && matchingItem.children) {
        updatedItem.children = copyUuidFromItemToSelectedItem(selectedItem.children, matchingItem.children);
      }
      return updatedItem;
    } else {
      return selectedItem;
    }
  });
};


export const mergeSelectedItems = (base: TreeMenuItem[], overrides: TreeMenuItem[]): TreeMenuItem[] => {
  const baseMap = new Map<string, TreeMenuItem>();

  // Populate the map with nodes from the base array
  for (const node of base) {
    baseMap.set(node.uuid, { ...node });
  }

  // Process nodes from the overrides array
  for (const overrideNode of overrides) {
    if (baseMap.has(overrideNode.uuid)) {
      const baseNode = baseMap.get(overrideNode.uuid)!;

      // Merge children recursively if both nodes have children
      if (baseNode.children || overrideNode.children) {
        baseNode.children = mergeSelectedItems(
          baseNode.children || [],
          overrideNode.children || []
        );
      }
    } else {
      // Add new nodes from overrides if they don't exist in base
      baseMap.set(overrideNode.uuid, { ...overrideNode });
    }
  }

  // Convert the map back to an array
  return Array.from(baseMap.values());
};
