import { Component, Event, EventEmitter, h, Prop, State, Watch } from '@stencil/core';
import { queryPanelItemSuffix } from '@src/utils/mx-utils';
import { isNullOrUndefined } from '@src/utils/mx-utils/utils';
import { Item } from '@src/utils/mx-utils/calendar-service';

@Component({
  tag: 'mx-query-store',
  styleUrl: 'mx-query-store.css',
  shadow: false
})
export class MxQueryStore {
  /** Sets the query store. */
  @Prop() readonly queryStore = {};
  /** Sets the item selected. */
  @Prop() readonly itemSelected: Item;
  /** Sets whether the form value has been changed or not. */
  @Prop() readonly isFormValueUnchanged?: boolean = false;
  /** Sets an id that prefixes the modal name. */
  @Prop() readonly modalIdPrefix?: string;

  /** Emits event when the query store is saved. */
  @Event() saveQueryStore: EventEmitter;
  /** Emits event when the query store is reset. */
  @Event() resetQueryStore: EventEmitter<Item>;
  /** Emits event when there is a change in the query store. */
  @Event() changeQueryStore: EventEmitter<MouseEvent>;
  /** Emits event when an item is removed from the query store. */
  @Event() removeQueryStore: EventEmitter<MouseEvent>;
  /** Emits event when an item is favorited in the query store. */
  @Event() favouriteQueryStore: EventEmitter<MouseEvent>;

  @State() isSaveMode: boolean = false;
  @State() isEditMode: boolean = false;
  @State() isInvalidQueryName: boolean = false;
  @State() queryName: string = '';
  @State() actionItem: any = null;
  @State() itemSelectedFavourite: boolean;

  private readonly confirmModalName = '_confirm-modal';

  @Watch('isFormValueUnchanged')
  watchFormValueUnchanged(newValue: boolean) {
    this.updateQueryName(newValue);
  }

  @Watch('itemSelected')
  watchItemSelected() {
    this.updateQueryName(this.isFormValueUnchanged);
    this.itemSelectedFavourite =
      (this.isSaveMode || this.isEditMode) &&
      this.itemSelected != null &&
      this.queryStore[this.itemSelected.value as string].serviceData?.favourite;
  }

  private readonly cancelNameForm = () => {
    if (this.isEditMode) {
      this.isEditMode = false;
      return;
    }
    if (this.isSaveMode) {
      this.isSaveMode = false;
      this.isInvalidQueryName = false;
      this.itemSelectedFavourite = false;
      this.updateQueryName(this.isFormValueUnchanged);
    }
  };

  private toggleSaveMode() {
    this.isSaveMode = !this.isSaveMode;
    this.isInvalidQueryName = false;
    this.itemSelectedFavourite =
      (this.isSaveMode || this.isEditMode) &&
      this.itemSelected != null &&
      this.queryStore[this.itemSelected.value as string].serviceData?.favourite;
    this.updateQueryName(this.isFormValueUnchanged);
  }

  private updateQueryName(isUnchanged: boolean) {
    if (isUnchanged) {
      this.queryName = this.itemSelected == null ? '' : (this.itemSelected.value as string);
    } else {
      if ((this.queryName === this.itemSelected?.value && this.isEditMode) || this.isSaveMode) {
        this.queryName = !isNullOrUndefined(this.itemSelected?.value)
          ? `${this.itemSelected?.value} ${queryPanelItemSuffix.MODIFIED_SUFFIX}`
          : '';
      }
    }
  }

  private readonly changeQueryName = (event: InputEvent) => {
    this.queryName = (event.target as HTMLInputElement).value;
  };

  private readonly updateQueryStore = () => {
    if (this.queryName && this.queryName.trim().length > 0) {
      this.saveQueryStore.emit({
        name: this.queryName,
        favourite: this.itemSelectedFavourite
      });
      if (this.isEditMode && this.queryName !== this.itemSelected.value) {
        this.removeQueryStore.emit(this.itemSelected as any);
      }
      this.isSaveMode = false;
      this.isEditMode = false;
      this.isInvalidQueryName = false;
      this.queryName = '';
    } else {
      this.isInvalidQueryName = true;
    }
  };
  private readonly handleItemChange = (event: CustomEvent) => {
    this.changeQueryStore.emit(event.detail);
  };

  private readonly handleOnResetLink = (e: MouseEvent) => {
    e?.preventDefault();
    if (
      !(
        this.isFormValueUnchanged ||
        !(this.itemSelected && this.queryStore.hasOwnProperty(this.itemSelected?.value as string))
      )
    ) {
      this.resetQueryStore.emit(this.itemSelected);
    }
  };


  private readonly handleOnSaveLink = () => {
    if (!(this.isFormValueUnchanged || this.isEditMode || this.isSaveMode)) {
      this.toggleSaveMode();
    }
  };
  private readonly onConfirmDelete = async () => {
    this.removeQueryStore.emit(this.actionItem);
    const selector = `mx-modal#${this.modalIdPrefix}${this.confirmModalName}`;
    const modal: HTMLMxModalElement = document.querySelector(selector);
    await modal.dismissModal();
    this.isEditMode = false;
    this.isSaveMode = false;
  };
  private readonly handleOnMakeDefault = (event: Event) => {
    const target = (event.target as HTMLInputElement);
    this.itemSelectedFavourite = target.checked;
  };

  render() {
    const queryKeys = Object.keys(this.queryStore);

    const disabledResetLink = this.isFormValueUnchanged ||
      !(this.itemSelected && this.queryStore.hasOwnProperty(this.itemSelected?.value as string));
    const disabledSaveLink = this.isFormValueUnchanged || this.isEditMode || this.isSaveMode;
    return (
      <div class='query-store border-neutral-less-prominent'>
        <div class='query-store-container bg-primary'>
          <mx-single-select
            width='185px'
            list-width='100%'
            itemSelected={this.itemSelected}
            isCompact={true}
            items={
              queryKeys.length > 0
                ? [
                  {
                    label: 'Select One',
                    value: null
                  },
                  ...queryKeys.map((key: string) => {
                    const suffix: string = ` ${queryPanelItemSuffix.DEFAULT_SUFFIX}`;
                    const favourite: boolean = this.queryStore[key]?.serviceData?.favourite;
                    return {
                      label: favourite ? `${key}${suffix}` : key,
                      value: key
                    };
                  })
                ]
                : []
            }
            itemActions={[
              {
                icon: (item) => {
                  return this.queryStore[item.value]?.serviceData?.favourite
                    ? 'kds-icon-ratings-solid'
                    : 'kds-icon-ratings';
                },
                condition: (item) => item.value,
                className: 'text-accent-more-prominent',
                stopPropagation: (item: any) =>
                  !!this.queryStore[item.value]?.serviceData?.favourite || this.isEditMode || this.isSaveMode,
                closeDropDown: this.isEditMode || this.isSaveMode,
                handler: (item) => this.favouriteQueryStore.emit(item.value)
              },
              {
                icon: 'kds-icon-edit',
                condition: (item) => item.value,
                className: 'text-accent-more-prominent',
                handler: (item) => {
                  this.queryName = item.value as string;
                  this.itemSelectedFavourite =
                    this.queryStore[this.itemSelected.value as string].serviceData?.favourite;
                  this.isEditMode = true;
                }
              },
              {
                icon: 'kds-icon-trash',
                condition: (item) => item.value,
                className: 'text-negative-less-prominent',
                stopPropagation: () => true,
                closeDropDown: true,
                handler: (item) => {
                  this.actionItem = item;
                  const selector = `mx-modal#${this.modalIdPrefix}${this.confirmModalName}`;
                  const modal: HTMLMxModalElement = document.querySelector(selector);
                  modal.createModal();
                }
              }
            ]}
            filterSearchPlaceholder='Select One'
            displayFilterSearch={true}
            onItemChange={this.handleItemChange}></mx-single-select>

          <kds-link
            size='m'
            linkClass={ disabledResetLink ? 'disable-link text-quaternary' : '' }
            onClick={(e: MouseEvent) => this.handleOnResetLink(e)}>
            Reset
          </kds-link>

          <kds-link
            size='m'
            linkClass={ disabledSaveLink ? 'disable-link text-quaternary' : '' }
            onClick={this.handleOnSaveLink}>
            Save
          </kds-link>
        </div>

        {(this.isSaveMode || this.isEditMode) && (
          <div class='query-store-footer bg-primary border-neutral-less-prominent'>
            <mx-input-text-box
              label='Set Name'
              class='query-store-name-input'
              input-name='query-name'
              is-compact={true}
              has-error={this.isInvalidQueryName}
              value={this.queryName}
              custom-error-message='Please enter query name.'
              onInput={this.changeQueryName}></mx-input-text-box>
            <kds-label class='kds-Label kds-Label--hasRadioOrCheckbox'>
              <kds-checkbox
                id='favourite'
                name='favourite'
                onChange={this.handleOnMakeDefault}
                checked={this.itemSelectedFavourite}
              />
              Make Default
            </kds-label>

            <div class='query-store-footer-action'>
              <kds-button compact={true} onClick={this.cancelNameForm} kind='cancel'>
                Cancel
              </kds-button>

              <kds-button compact={true} onClick={this.updateQueryStore} kind='dominant' palette='brand'>
                Save
              </kds-button>
            </div>
          </div>
        )}

        <mx-modal
          id={this.modalIdPrefix + this.confirmModalName}
          class='query-store__confirm-modal'
          close-modal-on-overlay-click='true'
          headercontent='Delete Saved View?'
          footer-primary-button-kind='destructive'
          is-active-secondary-button='true'
          footer-primary-button-text='Yes, Delete'
          onApplyClick={this.onConfirmDelete}
          footer-secondary-button-text='Cancel'>
          This action cannot be undone.
        </mx-modal>
      </div>
    );
  }
}
