import { State, Watch } from '@stencil/core';
import { Component, Event, EventEmitter, h, Prop } from '@stencil/core';
import { isArray, isDate, isObject } from '@src/utils/mx-utils';
import { isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';
import { getAllChildrenFromList, isMenuItem } from '@src/mx-components/menu-item/mx-menu-item/menu-item-utils';

@Component({
  tag: 'mx-query-panel-tag'
})
export class MxQueryPanelTag {

  /** Selected item in the form. **/
  @Prop() readonly item: Object | any;
  @Watch('item')
  handleItemChange() {
    this.isMenuItem =
      isArray(this.item) && this.item.length > 0 ? isMenuItem(this.item[0]) :
        isMenuItem(this.item);
  }
  /** Field name of the form. **/
  @Prop() readonly field: string;

  /** value which need to be deleted **/
  @Event() deleteValue: EventEmitter<{ field: string, value: any }>;

  @State() isMenuItem: boolean = false;

  componentWillLoad() {
    this.isMenuItem =
      isArray(this.item) && this.item.length > 0 ? isMenuItem(this.item[0]) :
        isMenuItem(this.item);
  }

  private _deleteValue = (field, value) => (_event) => this.deleteValue.emit({ field, value });

  private zeroPad = (num, places) => String(num).padStart(places, '0');

  private itemToString = () => {
    let dateStr = `${this.item.calType} ${this.item.calYear}`;
    if (!isNullOrUndefinedOrEmptyString(this.item.quarter)) {
      dateStr = dateStr.concat(`/Q${this.zeroPad(this.item.quarter, 2)}`);
    }
    if (!isNullOrUndefinedOrEmptyString(this.item.period)) {
      dateStr = dateStr.concat(`/P${this.zeroPad(this.item.period, 2)}`);
    }
    if (!isNullOrUndefinedOrEmptyString(this.item.week)) {
      dateStr = dateStr.concat(`/W${this.zeroPad(this.item.week, 2)}`);
    }
    return dateStr;
  };

  private selectedItemToString = (selectedItem: any) => {
    if (selectedItem.children) {
      return selectedItem.children[0].label;
    } else {
      return selectedItem.label;
    }
  };

  private renderItemTag(item: any, itemName: string) {
    return (
      <kds-tag
        style={{ maxWidth: '100%' }}
        class='mt-8 mr-8 single'
        kind='action'
        title={itemName}
        remove-self='false'
        onTagRemoved={this._deleteValue(this.field, item)}>
        {itemName}
      </kds-tag>
    );
  }
  render() {
    return (
      <div class='mt-16'>
        <kds-label style={{ maxWidth: '100%' }} class='text-secondary'>
          {this.field}
        </kds-label>
        {isArray(this.item) && this.item.length > 0 ?
          <div>
            {this.isMenuItem ?
              getAllChildrenFromList(this.item).map((el) => this.renderItemTag(el, el)) :
              this.item.map((el) => this.renderItemTag(el, el))}
          </div>
          : ''}
        {isObject(this.item) && !this.isMenuItem ?
          !isNullOrUndefinedOrEmptyString(this.itemToString()) ?
            this.renderItemTag(this.item, this.itemToString()) :
            this.renderItemTag(this.item, this.item)
          : ''}
        {!isArray(this.item) && !isObject(this.item) && !isDate(this.item) ?
          this.renderItemTag(this.item, this.item)
          : ''}

        {isDate(this.item) ? this.renderItemTag(this.item, this.item.toDateString()) : ''}
        {isObject(this.item) && this.isMenuItem ?
          !isNullOrUndefinedOrEmptyString(this.itemToString()) ?
            this.renderItemTag(this.item, this.selectedItemToString(this.item)) :
            this.renderItemTag(this.item, this.item)
          : ''}
      </div>
    );

  }
}
